import React, { useState, useEffect } from "react";

const DesignerForm = ({ onSubmit, existingData, onCancel }) => {
  // Initialize form data; previousDesigns always as array
  const [formData, setFormData] = useState(
    existingData || { name: "", email: "", type: "", previousDesigns: [] }
  );

  useEffect(() => {
    if (existingData) {
      setFormData(existingData);
    }
  }, [existingData]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    // Ensure previousDesigns is an array
    const updatedData = {
      ...formData,
      previousDesigns: typeof formData.previousDesigns === "string"
        ? formData.previousDesigns.split(",").map((s) => s.trim())
        : formData.previousDesigns
    };

    onSubmit(updatedData);

    // Reset form if adding new designer
    if (!existingData) {
      setFormData({ name: "", email: "", type: "", previousDesigns: [] });
    }
  };

  return (
    <form className="form" onSubmit={handleSubmit}>
      <h3>{existingData ? "Update Designer" : "Add Designer"}</h3>

      <input
        name="name"
        placeholder="Name"
        value={formData.name}
        onChange={handleChange}
        required
      />

      <input
        name="email"
        type="email"
        placeholder="Email"
        value={formData.email}
        onChange={handleChange}
        required
      />

      {/* Dropdown for type */}
      <select
        name="type"
        value={formData.type}
        onChange={handleChange}
        required
      >
        <option value="">Select Type</option>
        <option value="Video Edit">Video Edit</option>
        <option value="Image Edit">Image Edit</option>
      </select>

      <input
        name="previousDesigns"
        placeholder="Previous Designs (comma separated)"
        value={Array.isArray(formData.previousDesigns) ? formData.previousDesigns.join(", ") : formData.previousDesigns}
        onChange={handleChange}
      />

      <button type="submit">{existingData ? "Update" : "Add"}</button>
      {onCancel && (
        <button type="button" className="cancel-btn" onClick={onCancel}>
          Cancel
        </button>
      )}
    </form>
  );
};

export default DesignerForm;
